export default const NOSE_ICON = "data:image/png;base64,";
function App() {
  const [view, setView] = useState('home');
  const [cart, setCart] = useState([]);
  const [cartOpen, setCartOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const addToCart = (item) => {
    setCart((prev) => {
      const key = `${item.product}-${item.size}-${item.scent}`;
      const existing = prev.find((i) => `${i.product}-${i.size}-${i.scent}` === key);
      if (existing) {
        return prev.map((i) =>
          `${i.product}-${i.size}-${i.scent}` === key ? { ...i, qty: i.qty + 1 } : i
        );
      }
      return [...prev, { ...item, qty: 1 }];
    });
    setCartOpen(true);
  };

  const updateQty = (idx, delta) => {
    setCart((prev) => {
      const next = [...prev];
      next[idx].qty += delta;
      if (next[idx].qty <= 0) next.splice(idx, 1);
      return next;
    });
  };

  const subtotal = cart.reduce((sum, i) => sum + i.price * i.qty, 0);

  return (
    <div style={{ fontFamily: "'Inter', system-ui, sans-serif", color: '#2A1F18', background: '#F7F1E8', minHeight: '100vh' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:ital,opsz,wght@0,9..144,300;0,9..144,400;0,9..144,500;0,9..144,600;0,9..144,700;1,9..144,400&family=Inter:wght@300;400;500;600;700&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        .display { font-family: 'Fraunces', Georgia, serif; font-optical-sizing: auto; letter-spacing: -0.02em; }
        .display-italic { font-family: 'Fraunces', Georgia, serif; font-style: italic; letter-spacing: -0.02em; }
        button { font-family: inherit; cursor: pointer; border: none; background: none; color: inherit; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slideIn { from { transform: translateX(100%); } to { transform: translateX(0); } }
        @keyframes shimmer { 0%, 100% { transform: rotate(0deg); } 50% { transform: rotate(3deg); } }
        .fade-up { animation: fadeUp 0.8s ease-out forwards; opacity: 0; }
        .delay-1 { animation-delay: 0.1s; }
        .delay-2 { animation-delay: 0.25s; }
        .delay-3 { animation-delay: 0.4s; }
        .delay-4 { animation-delay: 0.55s; }
        .delay-5 { animation-delay: 0.7s; }
        .hover-lift { transition: transform 0.4s cubic-bezier(.2,.8,.2,1), box-shadow 0.4s ease; }
        .hover-lift:hover { transform: translateY(-4px); }
        .btn-primary { background: #2A1F18; color: #F7F1E8; padding: 14px 32px; border-radius: 999px; font-weight: 500; font-size: 14px; letter-spacing: 0.05em; text-transform: uppercase; transition: all 0.3s ease; display: inline-flex; align-items: center; gap: 8px; }
        .btn-primary:hover { background: #C97B4F; transform: translateY(-2px); }
        .btn-outline { border: 1.5px solid #2A1F18; color: #2A1F18; padding: 14px 32px; border-radius: 999px; font-weight: 500; font-size: 14px; letter-spacing: 0.05em; text-transform: uppercase; transition: all 0.3s ease; display: inline-flex; align-items: center; gap: 8px; }
        .btn-outline:hover { background: #2A1F18; color: #F7F1E8; }
        .nav-link { font-size: 14px; font-weight: 500; letter-spacing: 0.02em; transition: color 0.2s; cursor: pointer; }
        .nav-link:hover { color: #C97B4F; }
        .blob { position: absolute; border-radius: 50%; filter: blur(80px); opacity: 0.4; z-index: 0; }
        .scent-dot { transition: transform 0.3s ease; }
        .scent-dot:hover { transform: scale(1.15); }
        .product-card { background: #FBF6EE; border-radius: 24px; overflow: hidden; cursor: pointer; transition: all 0.4s ease; }
        .product-card:hover { transform: translateY(-6px); box-shadow: 0 24px 60px -20px rgba(60, 40, 25, 0.25); }
        .marquee { display: flex; gap: 60px; animation: scroll 30s linear infinite; }
        @keyframes scroll { from { transform: translateX(0); } to { transform: translateX(-50%); } }
        input, select { font-family: inherit; }
        .input { width: 100%; padding: 14px 16px; border: 1.5px solid #E2D5C0; border-radius: 12px; background: #FBF6EE; font-size: 15px; color: #2A1F18; transition: border-color 0.2s; outline: none; }
        .input:focus { border-color: #C97B4F; }
        @media (max-width: 768px) {
          .hide-mobile { display: none !important; }
          .hero-title { font-size: 56px !important; }
        }
      `}</style>

      <Nav view={view} setView={setView} cartCount={cart.reduce((s, i) => s + i.qty, 0)} setCartOpen={setCartOpen} mobileMenuOpen={mobileMenuOpen} setMobileMenuOpen={setMobileMenuOpen} />

      {view === 'home' && <Home setView={setView} setSelectedProduct={setSelectedProduct} />}
      {view === 'shop' && <Shop setView={setView} setSelectedProduct={setSelectedProduct} />}
      {view === 'product' && <ProductDetail product={selectedProduct} addToCart={addToCart} setView={setView} />}
      {view === 'about' && <About />}
      {view === 'checkout' && <Checkout cart={cart} subtotal={subtotal} setView={setView} />}
      {view === 'confirmation' && <Confirmation setView={setView} setCart={setCart} />}

      <Footer setView={setView} />

      {cartOpen && (
        <Cart
          cart={cart}
          updateQty={updateQty}
          subtotal={subtotal}
          onClose={() => setCartOpen(false)}
          onCheckout={() => { setCartOpen(false); setView('checkout'); }}
        />
      )}
    </div>
  );
}

function Nav({ view, setView, cartCount, setCartOpen, mobileMenuOpen, setMobileMenuOpen }) {
  const go = (v) => { setView(v); setMobileMenuOpen(false); window.scrollTo(0, 0); };
  return (
    <nav style={{ position: 'sticky', top: 0, zIndex: 50, background: 'rgba(247, 241, 232, 0.85)', backdropFilter: 'blur(20px)', borderBottom: '1px solid rgba(42, 31, 24, 0.08)' }}>
      <div style={{ maxWidth: 1400, margin: '0 auto', padding: '20px 32px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <button onClick={() => go('home')} className="display" style={{ fontSize: 22, fontWeight: 600, letterSpacing: '-0.03em', display: 'flex', alignItems: 'center', gap: 12 }}>
          <img src={IMAGES.logo} alt="Not Another Body Butter logo" style={{ height: 46, width: 46, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }} />
          <span>Not Another<span style={{ fontStyle: 'italic', color: '#C97B4F' }}> Body Butter</span></span>
        </button>
        <div className="hide-mobile" style={{ display: 'flex', gap: 36, alignItems: 'center' }}>
          <button className="nav-link" onClick={() => go('shop')}>Shop</button>
          <button className="nav-link" onClick={() => go('about')}>Our Story</button>
          <button className="nav-link" onClick={() => go('shop')}>Scents</button>
          <button className="nav-link" onClick={() => setCartOpen(true)} style={{ position: 'relative', display: 'flex', alignItems: 'center', gap: 6 }}>
            <ShoppingBag size={18} />
            {cartCount > 0 && (
              <span style={{ position: 'absolute', top: -8, right: -10, background: '#C97B4F', color: '#FBF6EE', borderRadius: '50%', width: 18, height: 18, fontSize: 11, display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600 }}>{cartCount}</span>
            )}
          </button>
        </div>
        <button className="hide-mobile" style={{ display: 'none' }} onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
          <Menu size={22} />
        </button>
        <div style={{ display: 'none' }} className="show-mobile-flex">
          <button onClick={() => setCartOpen(true)} style={{ position: 'relative', display: 'flex', alignItems: 'center', gap: 6 }}>
            <ShoppingBag size={20} />
            {cartCount > 0 && (
              <span style={{ position: 'absolute', top: -6, right: -8, background: '#C97B4F', color: '#FBF6EE', borderRadius: '50%', width: 16, height: 16, fontSize: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600 }}>{cartCount}</span>
            )}
          </button>
        </div>
      </div>
    </nav>
  );
}

